jQuery(document).ready(function(s){s(".approval-toggle").on("change",function(){const t=s(this).closest("tr").data("id"),e=s(this).prop("checked");s.ajax({url:ajaxurl,type:"POST",data:{action:"update_submission_approval",id:t,approved:e},success:function(i){i.success?alert("Status updated successfully!"):alert("Error updating status.")}})}),s(".view-details").on("click",function(){const a=s(this).closest("tr").data("id");window.location.href=`admin.php?page=show-submission-details&id=${a}`}),s(".add-to-media-library").on("click",function(){const a=s(this),t=a.data("filename"),e=new URLSearchParams(window.location.search).get("id");a.prop("disabled",!0).text("Processing..."),s.ajax({url:showSubmissionsAdmin.ajaxurl,type:"POST",data:{action:"add_to_media_library",nonce:showSubmissionsAdmin.nonce,filename:t,submission_id:e},success:function(i){i.success?a.closest(".submission-image").fadeOut():(alert("Error: "+i.data),a.prop("disabled",!1).text("Add to Media Library"))},error:function(){alert("Error processing request"),a.prop("disabled",!1).text("Add to Media Library")}})})});
